import React, { useState, useEffect, useCallback } from 'react';
import { useWeb3 } from '../contexts/Web3Context';
import { useSettings } from '../contexts/SettingsContext';
import { NETWORKS, BRIDGE_CONFIG } from '../config/networks';
import { getTokenBalance, isValidAddress, isValidAmount } from '../utils/web3';
import { createBridgeContract, getRequiredStakeInOriginalToken, transferToForeignChain } from '../utils/bridge-contracts';
import { AlertCircle, Calculator, ArrowDown } from 'lucide-react';
import { motion } from 'framer-motion';

const BridgeForm = () => {
  const { account, provider, signer, network, isConnected } = useWeb3();
  const { getNetworkWithSettings, getBridgeInstancesWithSettings, getStakeTokenSymbol } = useSettings();

  const [formData, setFormData] = useState({
    homeNetwork: '',
    homeTokenSymbol: '',
    foreignNetwork: '',
    foreignTokenSymbol: '',
    amount: '',
    destinationAddress: '',
    reward: '0',
  });

  const [balances, setBalances] = useState({});
  const [requiredStake, setRequiredStake] = useState('0');
  const [stakeTokenSymbol, setStakeTokenSymbol] = useState('');
  const [actualStakeRatio, setActualStakeRatio] = useState(15);
  const [extraStakeAmount, setExtraStakeAmount] = useState('0');
  const [isLoading, setIsLoading] = useState(false);
  const [errors, setErrors] = useState({});

  // Get available networks excluding current network
  const getAvailableNetworks = () => {
    if (!network) return Object.values(NETWORKS);
    return Object.values(NETWORKS).filter(n => n.id !== network.id);
  };

  // Get available routes for a given home network and token
  const getAvailableRoutes = useCallback((homeNetwork, homeTokenSymbol) => {
    const bridgeInstances = getBridgeInstancesWithSettings();
    return Object.values(bridgeInstances).filter(bridge => 
      bridge.homeNetwork === homeNetwork && 
      bridge.homeTokenSymbol === homeTokenSymbol
    );
  }, [getBridgeInstancesWithSettings]);

  // Get available foreign networks for a given home network and token
  const getAvailableForeignNetworks = useCallback((homeNetwork, homeTokenSymbol) => {
    const routes = getAvailableRoutes(homeNetwork, homeTokenSymbol);
    const foreignNetworks = routes.map(route => route.foreignNetwork);

    // Get network objects for the foreign networks
    return Object.values(NETWORKS).filter(net => 
      foreignNetworks.includes(net.symbol)
    );
  }, [getAvailableRoutes]);

  // Get available foreign tokens for a given route
  const getAvailableForeignTokens = useCallback((homeNetwork, homeTokenSymbol, foreignNetwork) => {
    const routes = getAvailableRoutes(homeNetwork, homeTokenSymbol);
    const route = routes.find(r => r.foreignNetwork === foreignNetwork);

    if (!route) return [];

    // Get the foreign token from the route
    const foreignTokenSymbol = route.foreignTokenSymbol;

    // Get the network configuration for the foreign network
    const networkKey = Object.keys(NETWORKS).find(key => NETWORKS[key].symbol === foreignNetwork);
    if (!networkKey) return [];

    const network = getNetworkWithSettings(networkKey);
    if (!network) return [];

    // Find the specific token in the network's tokens
    const token = Object.values(network.tokens).find(t => t.symbol === foreignTokenSymbol);
    return token ? [token] : [];
  }, [getAvailableRoutes, getNetworkWithSettings]);

  // Get bridge instance for the selected route
  const getBridgeInstanceForRoute = useCallback((homeNetwork, homeTokenSymbol, foreignNetwork, foreignTokenSymbol) => {
    const bridgeInstances = getBridgeInstancesWithSettings();
    return Object.values(bridgeInstances).find(bridge => 
      bridge.homeNetwork === homeNetwork &&
      bridge.homeTokenSymbol === homeTokenSymbol &&
      bridge.foreignNetwork === foreignNetwork &&
      bridge.foreignTokenSymbol === foreignTokenSymbol
    );
  }, [getBridgeInstancesWithSettings]);

  // Get available tokens for a network
  const getAvailableTokens = useCallback((networkSymbol) => {
    if (!networkSymbol) return [];
    const networkKey = Object.keys(NETWORKS).find(key => NETWORKS[key].symbol === networkSymbol);
    if (!networkKey) return [];

    const network = getNetworkWithSettings(networkKey);
    if (!network) return [];

    // For 3DPass, all tokens are ERC20 precompiles
    if (networkSymbol === '3DPass') {
      return Object.values(network.tokens);
    }

    // For other networks, include native token
    const tokens = [
      {
        address: '0x0000000000000000000000000000000000000000',
        symbol: network.nativeCurrency.symbol,
        name: network.nativeCurrency.name,
        decimals: network.nativeCurrency.decimals,
        isNative: true,
      },
      ...Object.values(network.tokens),
    ];

    return tokens;
  }, [getNetworkWithSettings]);

  // Load balances
  const loadBalances = useCallback(async () => {
    if (!account || !provider || !formData.homeNetwork) return;

    const tokens = getAvailableTokens(formData.homeNetwork);
    const newBalances = {};

    for (const token of tokens) {
      try {
        const balance = await getTokenBalance(
          provider,
          token.address,
          account,
          token.decimals,
          token.isPrecompile
        );
        newBalances[token.symbol] = balance;
      } catch (error) {
        console.error(`Error loading balance for ${token.symbol}:`, error);
        newBalances[token.symbol] = '0';
      }
    }

    setBalances(newBalances);
  }, [account, provider, formData.homeNetwork, getAvailableTokens]);

  // Calculate required stake using actual contract ratio when available
  const calculateStake = useCallback(async () => {
    if (!formData.amount || !isValidAmount(formData.amount)) {
      setRequiredStake('0');
      setActualStakeRatio(15);
      setExtraStakeAmount('0');
      setStakeTokenSymbol('');
      return;
    }

    try {
      // Try to get stake from contract if available
      if (formData.homeNetwork && formData.homeTokenSymbol && formData.foreignNetwork && formData.foreignTokenSymbol && provider) {
        // Find the specific bridge instance for this transfer
        const bridgeInstance = getBridgeInstanceForRoute(formData.homeNetwork, formData.homeTokenSymbol, formData.foreignNetwork, formData.foreignTokenSymbol);

        if (bridgeInstance) {
          const contract = createBridgeContract(provider, bridgeInstance.address, formData.homeNetwork, 'export');
          const token = getAvailableTokens(formData.homeNetwork).find(t => t.symbol === formData.homeTokenSymbol);

          // Get the required stake first (in original token units)
          const stake = await getRequiredStakeInOriginalToken(
            contract, 
            formData.amount, 
            token?.decimals || 18
          );

          setRequiredStake(stake);

          // Get stake token symbol from bridge instance
          const bridgeStakeTokenSymbol = getStakeTokenSymbol(bridgeInstance);
          setStakeTokenSymbol(bridgeStakeTokenSymbol || formData.homeTokenSymbol);

          // Calculate extra stake amount for display
          const transferAmount = parseFloat(formData.amount);
          const fullStakeAmount = parseFloat(stake);
          const extraAmount = fullStakeAmount - transferAmount;
          setExtraStakeAmount(extraAmount.toFixed(6));

          // Try to get the ratio from contract settings
          try {
            const settings = await contract.settings();
            setActualStakeRatio(settings.ratio100);
          } catch (settingsError) {
            console.log('Settings() failed, calculating ratio from stake amount:', settingsError.message);

            const amount = parseFloat(formData.amount);
            const stakeAmount = parseFloat(stake);
            const actualStakeRatio = ((stakeAmount - amount) / amount) * 100;

            setActualStakeRatio(Math.round(actualStakeRatio * 100) / 100);
          }
          return;
        }
      }

      // Fallback to default calculation when contract is not available
      const amount = parseFloat(formData.amount);
      const stakeRatio = BRIDGE_CONFIG.defaultStakeRatio / 100;
      const stake = amount * stakeRatio;

      setRequiredStake(stake.toFixed(6));
      setStakeTokenSymbol(formData.homeTokenSymbol);
      setActualStakeRatio(BRIDGE_CONFIG.defaultStakeRatio);

      const extraAmount = parseFloat(stake) - amount;
      setExtraStakeAmount(extraAmount.toFixed(6));
    } catch (error) {
      console.error('Error calculating stake:', error);
      // Fallback to default calculation
      const amount = parseFloat(formData.amount);
      const stakeRatio = BRIDGE_CONFIG.defaultStakeRatio / 100;
      const stake = amount * stakeRatio;
      setRequiredStake(stake.toFixed(6));
      setStakeTokenSymbol(formData.homeTokenSymbol);
      setActualStakeRatio(BRIDGE_CONFIG.defaultStakeRatio);

      const extraAmount = parseFloat(stake) - amount;
      setExtraStakeAmount(extraAmount.toFixed(6));
    }
  }, [formData.amount, formData.homeNetwork, formData.homeTokenSymbol, formData.foreignNetwork, formData.foreignTokenSymbol, provider, getAvailableTokens, getBridgeInstanceForRoute, getStakeTokenSymbol]);

  // Handle form changes
  const handleInputChange = (field, value) => {
    setFormData(prev => ({ ...prev, [field]: value }));

    // Clear related fields when network changes
    if (field === 'homeNetwork') {
      setFormData(prev => ({
        ...prev,
        homeTokenSymbol: '',
        foreignNetwork: '',
        foreignTokenSymbol: '',
        amount: '',
      }));
    } else if (field === 'foreignNetwork') {
      setFormData(prev => ({
        ...prev,
        foreignTokenSymbol: '',
      }));
    }

    // Clear errors
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  // Validate form
  const validateForm = () => {
    const newErrors = {};

    if (!formData.homeNetwork) {
      newErrors.homeNetwork = 'Please select home network';
    }

    if (!formData.homeTokenSymbol) {
      newErrors.homeTokenSymbol = 'Please select home token';
    }

    if (!formData.foreignNetwork) {
      newErrors.foreignNetwork = 'Please select foreign network';
    }

    if (!formData.foreignTokenSymbol) {
      newErrors.foreignTokenSymbol = 'Please select foreign token';
    }

    // Validate that the selected route exists
    if (formData.homeNetwork && formData.homeTokenSymbol && formData.foreignNetwork && formData.foreignTokenSymbol) {
      const bridgeInstance = getBridgeInstanceForRoute(formData.homeNetwork, formData.homeTokenSymbol, formData.foreignNetwork, formData.foreignTokenSymbol);
      if (!bridgeInstance) {
        newErrors.general = 'Selected route is not available. Please choose a valid combination of networks and tokens.';
      }
    }

    if (!formData.amount || !isValidAmount(formData.amount)) {
      newErrors.amount = 'Please enter a valid amount';
    } else {
      const amount = parseFloat(formData.amount);
      const transferBalance = parseFloat(balances[formData.homeTokenSymbol] || '0');
      const stakeBalance = parseFloat(balances[stakeTokenSymbol || formData.homeTokenSymbol] || '0');
      const stakeAmount = parseFloat(requiredStake);

      if (amount > transferBalance) {
        newErrors.amount = `Insufficient ${formData.homeTokenSymbol} balance. You need ${amount.toFixed(6)} ${formData.homeTokenSymbol}`;
      } else if (stakeAmount > stakeBalance) {
        newErrors.amount = `Insufficient ${stakeTokenSymbol || formData.homeTokenSymbol} balance for stake. You need ${stakeAmount.toFixed(6)} ${stakeTokenSymbol || formData.homeTokenSymbol}`;
      }
    }

    if (!formData.destinationAddress) {
      newErrors.destinationAddress = 'Please enter destination address';
    } else if (!isValidAddress(formData.destinationAddress)) {
      newErrors.destinationAddress = 'Please enter a valid address';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!isConnected) {
      setErrors({ general: 'Please connect your wallet first' });
      return;
    }

    if (!validateForm()) {
      return;
    }

    setIsLoading(true);
    setErrors({});

    try {
      // Get network and token information
      const homeNetwork = Object.values(NETWORKS).find(n => n.symbol === formData.homeNetwork);
      const homeToken = getAvailableTokens(formData.homeNetwork).find(t => t.symbol === formData.homeTokenSymbol);

      if (!homeNetwork || !homeToken) {
        throw new Error('Invalid network or token configuration');
      }

      // Find the specific bridge instance for this transfer
      const bridgeInstance = getBridgeInstanceForRoute(formData.homeNetwork, formData.homeTokenSymbol, formData.foreignNetwork, formData.foreignTokenSymbol);

      if (!bridgeInstance) {
        throw new Error('No bridge instance found for this transfer route');
      }

      // Create bridge contract using the specific bridge instance
      const contract = createBridgeContract(signer, bridgeInstance.address, formData.homeNetwork, 'export');

      // Execute transfer
      const receipt = await transferToForeignChain(
        contract,
        formData.destinationAddress,
        '', // data
        formData.amount,
        formData.reward,
        homeToken.decimals,
        homeToken.isPrecompile
      );

      console.log('Transfer successful:', receipt);

      // Reset form
      setFormData({
        homeNetwork: '',
        homeTokenSymbol: '',
        foreignNetwork: '',
        foreignTokenSymbol: '',
        amount: '',
        destinationAddress: '',
        reward: '0',
      });

      // Show success message
      setErrors({ success: 'Transfer initiated successfully! Check your transaction hash.' });

    } catch (error) {
      console.error('Transfer failed:', error);
      setErrors({ general: error.message });
    } finally {
      setIsLoading(false);
    }
  };

  // Load balances when account or home network changes
  useEffect(() => {
    loadBalances();
  }, [loadBalances]);

  // Calculate stake when amount changes
  useEffect(() => {
    calculateStake();
  }, [calculateStake]);

  // Auto-fill destination address with current account
  useEffect(() => {
    if (account && !formData.destinationAddress) {
      setFormData(prev => ({ ...prev, destinationAddress: account }));
    }
  }, [account, formData.destinationAddress]);

  const availableNetworks = getAvailableNetworks();
  const homeTokens = getAvailableTokens(formData.homeNetwork);
  const foreignNetworks = formData.homeNetwork && formData.homeTokenSymbol 
    ? getAvailableForeignNetworks(formData.homeNetwork, formData.homeTokenSymbol)
    : [];
  const foreignTokens = formData.homeNetwork && formData.homeTokenSymbol && formData.foreignNetwork
    ? getAvailableForeignTokens(formData.homeNetwork, formData.homeTokenSymbol, formData.foreignNetwork)
    : [];

  return (
    <div className="max-w-4xl mx-auto">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="card"
      >
        <div className="mb-6">
          <h2 className="text-2xl font-bold text-white mb-2">Cross-Chain Transfer</h2>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Error Message */}
          {errors.general && (
            <div className="bg-error-900/50 border border-error-700 rounded-lg p-4 flex items-start space-x-3">
              <AlertCircle className="w-5 h-5 text-error-400 mt-0.5 flex-shrink-0" />
              <div>
                <h3 className="text-error-400 font-medium">Transfer Failed</h3>
                <p className="text-error-300 text-sm mt-1">{errors.general}</p>
              </div>
            </div>
          )}

          {/* Success Message */}
          {errors.success && (
            <div className="bg-success-900/50 border border-success-700 rounded-lg p-4 flex items-start space-x-3">
              <div className="w-5 h-5 bg-success-500 rounded-full mt-0.5 flex-shrink-0"></div>
              <div>
                <h3 className="text-success-400 font-medium">Transfer Successful</h3>
                <p className="text-success-300 text-sm mt-1">{errors.success}</p>
              </div>
            </div>
          )}

          {/* Home Network & Token */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-white mb-2">
                Home Network
              </label>
              <select
                value={formData.homeNetwork}
                onChange={(e) => handleInputChange('homeNetwork', e.target.value)}
                className={`input-field w-full ${errors.homeNetwork ? 'border-error-500' : ''}`}
              >
                <option value="">Select network</option>
                {availableNetworks.map((net) => (
                  <option key={net.id} value={net.symbol}>
                    {net.name}
                  </option>
                ))}
              </select>
              {errors.homeNetwork && (
                <p className="text-error-400 text-sm mt-1">{errors.homeNetwork}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-white mb-2">
                Home Token
              </label>
              <select
                value={formData.homeTokenSymbol}
                onChange={(e) => handleInputChange('homeTokenSymbol', e.target.value)}
                className={`input-field w-full ${errors.homeTokenSymbol ? 'border-error-500' : ''}`}
                disabled={!formData.homeNetwork}
              >
                <option value="">Select token</option>
                {homeTokens.map((token) => (
                  <option key={token.symbol} value={token.symbol}>
                    {token.symbol} - {token.name}
                  </option>
                ))}
              </select>
              {formData.homeTokenSymbol && balances[formData.homeTokenSymbol] && (
                <p className="text-secondary-400 text-sm mt-1">
                  Balance: {parseFloat(balances[formData.homeTokenSymbol]).toFixed(6)} {formData.homeTokenSymbol}
                </p>
              )}
              {errors.homeTokenSymbol && (
                <p className="text-error-400 text-sm mt-1">{errors.homeTokenSymbol}</p>
              )}
            </div>
          </div>

          {/* Arrow */}
          <div className="flex justify-center">
            <div className="w-12 h-12 bg-dark-800 rounded-full flex items-center justify-center border border-secondary-700">
              <ArrowDown className="w-6 h-6 text-secondary-400" />
            </div>
          </div>

          {/* Foreign Network & Token */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-white mb-2">
                Foreign Network
              </label>
              <select
                value={formData.foreignNetwork}
                onChange={(e) => handleInputChange('foreignNetwork', e.target.value)}
                className={`input-field w-full ${errors.foreignNetwork ? 'border-error-500' : ''}`}
                disabled={!formData.homeNetwork || !formData.homeTokenSymbol}
              >
                <option value="">Select network</option>
                {foreignNetworks.length > 0 ? (
                  foreignNetworks.map((net) => (
                    <option key={net.id} value={net.symbol}>
                      {net.name}
                    </option>
                  ))
                ) : (
                  <option value="" disabled>
                    {formData.homeNetwork && formData.homeTokenSymbol 
                      ? 'No routes available for this token' 
                      : 'Select home network and token first'
                    }
                  </option>
                )}
              </select>
              {errors.foreignNetwork && (
                <p className="text-error-400 text-sm mt-1">{errors.foreignNetwork}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-white mb-2">
                Foreign Token
              </label>
              <select
                value={formData.foreignTokenSymbol}
                onChange={(e) => handleInputChange('foreignTokenSymbol', e.target.value)}
                className={`input-field w-full ${errors.foreignTokenSymbol ? 'border-error-500' : ''}`}
                disabled={!formData.foreignNetwork}
              >
                <option value="">Select token</option>
                {foreignTokens.length > 0 ? (
                  foreignTokens.map((token) => (
                    <option key={token.symbol} value={token.symbol}>
                      {token.symbol} - {token.name}
                    </option>
                  ))
                ) : (
                  <option value="" disabled>
                    {formData.foreignNetwork 
                      ? 'No tokens available for this route' 
                      : 'Select foreign network first'
                    }
                  </option>
                )}
              </select>
              {errors.foreignTokenSymbol && (
                <p className="text-error-400 text-sm mt-1">{errors.foreignTokenSymbol}</p>
              )}
            </div>
          </div>

          {/* Amount & Destination Address */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-white mb-2">
                Amount
              </label>
              <input
                type="number"
                value={formData.amount}
                onChange={(e) => handleInputChange('amount', e.target.value)}
                placeholder="0.0"
                step="0.000001"
                className={`input-field w-full ${errors.amount ? 'border-error-500' : ''}`}
              />
              {errors.amount && (
                <p className="text-error-400 text-sm mt-1">{errors.amount}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-white mb-2">
                Destination Address
              </label>
              <input
                type="text"
                value={formData.destinationAddress}
                onChange={(e) => handleInputChange('destinationAddress', e.target.value)}
                placeholder="0x..."
                className={`input-field w-full font-mono ${errors.destinationAddress ? 'border-error-500' : ''}`}
              />
              {errors.destinationAddress && (
                <p className="text-error-400 text-sm mt-1">{errors.destinationAddress}</p>
              )}
            </div>
          </div>

          {/* Stake Information */}
          <div className="bg-dark-800 rounded-lg p-4 border border-secondary-700">
            <div className="flex items-center space-x-2 mb-3">
              <Calculator className="w-4 h-4 text-secondary-400" />
              <h3 className="text-sm font-medium text-white">Stake Information</h3>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
              <div>
                <p className="text-secondary-400">Required Stake</p>
                <p className="text-white font-mono">{requiredStake} {stakeTokenSymbol || formData.homeTokenSymbol}</p>
              </div>
              <div>
                <p className="text-secondary-400">Stake Ratio</p>
                <p className="text-white">{actualStakeRatio}%</p>
              </div>
              <div>
                <p className="text-secondary-400">Total Required</p>
                <p className="text-white font-mono">
                  {formData.amount && requiredStake !== '0' 
                    ? `${parseFloat(formData.amount).toFixed(6)} ${formData.homeTokenSymbol} + ${extraStakeAmount} ${stakeTokenSymbol || formData.homeTokenSymbol}`
                    : '0'
                  }
                </p>
              </div>
            </div>
          </div>

          {/* Reward (Optional) */}
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              Reward for Assistant (Optional)
            </label>
            <input
              type="number"
              value={formData.reward}
              onChange={(e) => handleInputChange('reward', e.target.value)}
              placeholder="0.0"
              step="0.000001"
              className="input-field w-full"
            />
            <p className="text-secondary-400 text-sm mt-1">
              Optional reward to incentivize assistants to process your transfer faster
            </p>
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            disabled={isLoading || !isConnected}
            className="w-full btn-primary py-3 text-lg font-medium disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isLoading ? (
              <div className="flex items-center justify-center space-x-2">
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                <span>Processing Transfer...</span>
              </div>
            ) : (
              'Initiate Transfer'
            )}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default BridgeForm;
